import React, { useState, useEffect } from "react";
// Si usas React Router, puedes usar Link para navegar al formulario de creación
import { Link } from "react-router-dom"; 

export default function Proveedores() {
  // Estados para guardar los datos y manejar la pantalla de carga
  const [proveedores, setProveedores] = useState([]);
  const [cargando, setCargando] = useState(true);

  // Efecto que se ejecuta al cargar la pantalla
  useEffect(() => {
    obtenerProveedores();
  }, []);

  const obtenerProveedores = async () => {
    try {
      // Petición a tu backend
      const respuesta = await fetch("http://localhost:5000/api/proveedores"); // Ajusta el puerto si es diferente
      const datos = await respuesta.json();
      
      setProveedores(datos);
      setCargando(false);
    } catch (error) {
      console.error("Error al cargar los proveedores:", error);
      setCargando(false);
    }
  };

  const eliminarProveedor = async (id) => {
    if (window.confirm("¿Estás seguro de que deseas desactivar este proveedor?")) {
      try {
        await fetch(`http://localhost:5000/api/proveedores/${id}`, {
          method: "DELETE",
        });
        // Recargamos la lista después de eliminar
        obtenerProveedores();
      } catch (error) {
        console.error("Error al eliminar:", error);
      }
    }
  };

  return (
    <div className="container-fluid p-4" style={{ marginLeft: "250px", width: "calc(100% - 250px)" }}>
      {/* Encabezado y Botón Nuevo */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h2 className="fw-bold">Gestión de Proveedores</h2>
          <p className="text-muted">Administra las empresas que surten tu negocio</p>
        </div>
        
        {/* Aquí puedes usar un Link si haces una pantalla nueva, o un botón si usas un Modal */}
        <Link to="/proveedores/nuevo" className="btn btn-primary d-flex align-items-center shadow-sm">
          <span className="me-2">+</span> Nuevo Proveedor
        </Link>
      </div>

      {/* Tarjeta con la Tabla */}
      <div className="card shadow-sm border-0">
        <div className="card-body p-0">
          {cargando ? (
            <div className="text-center p-5">
              <div className="spinner-border text-primary" role="status">
                <span className="visually-hidden">Cargando...</span>
              </div>
            </div>
          ) : (
            <div className="table-responsive">
              <table className="table table-hover align-middle mb-0">
                <thead className="table-light">
                  <tr>
                    <th className="px-4 py-3">Empresa</th>
                    <th className="py-3">Contacto</th>
                    <th className="py-3">Teléfono</th>
                    <th className="py-3">Email</th>
                    <th className="px-4 py-3 text-end">Acciones</th>
                  </tr>
                </thead>
                <tbody>
                  {proveedores.length === 0 ? (
                    <tr>
                      <td colSpan="5" className="text-center py-4 text-muted">
                        No hay proveedores registrados todavía.
                      </td>
                    </tr>
                  ) : (
                    proveedores.map((proveedor) => (
                      <tr key={proveedor._id}>
                        <td className="px-4 fw-medium">{proveedor.nombreEmpresa}</td>
                        <td>{proveedor.nombreContacto || "N/A"}</td>
                        <td>{proveedor.telefono || "N/A"}</td>
                        <td>{proveedor.email || "N/A"}</td>
                        <td className="px-4 text-end">
                          <Link 
                            to={`/proveedores/editar/${proveedor._id}`} 
                            className="btn btn-sm btn-outline-secondary me-2"
                          >
                            ✏️
                          </Link>
                          <button 
                            onClick={() => eliminarProveedor(proveedor._id)} 
                            className="btn btn-sm btn-outline-danger"
                          >
                            🗑️
                          </button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
